import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Cloudflare R2 चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/cloudflare-r2.md","filePath":"hi/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"hi/upload/cloudflare-r2.md"};function c(u,e,s,p,h,b){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-r2-चैनल-जोड़ना" tabindex="-1">Cloudflare R2 चैनल जोड़ना <a class="header-anchor" href="#cloudflare-r2-चैनल-जोड़ना" aria-label="Permalink to &quot;Cloudflare R2 चैनल जोड़ना&quot;">​</a></h1><h2 id="कब-सबसे-सही-है" tabindex="-1">कब सबसे सही है <a class="header-anchor" href="#कब-सबसे-सही-है" aria-label="Permalink to &quot;कब सबसे सही है&quot;">​</a></h2><p>Cloudflare R2 का उपयोग तब करें जब:</p><ul><li>आपका ImgBed site पहले से Cloudflare पर deployed है और आप उसी Cloudflare account के R2 bucket में files रखना चाहते हैं।</li><li>आप अलग S3 endpoint, access key और secret key configure नहीं करना चाहते।</li><li>आप चाहते हैं कि पढ़ना और लिखना Worker या Pages R2 binding से कम setup में हो जाए।</li></ul><p>संक्षेप में:</p><p>R2 channel ImgBed admin panel में manually create नहीं होता। पहले आपको Cloudflare project से R2 bucket bind करना होता है, और binding variable name बिल्कुल <code>img_r2</code> होना चाहिए।</p><h2 id="शुरू-करने-से-पहले-क्या-चाहिए" tabindex="-1">शुरू करने से पहले क्या चाहिए <a class="header-anchor" href="#शुरू-करने-से-पहले-क्या-चाहिए" aria-label="Permalink to &quot;शुरू करने से पहले क्या चाहिए&quot;">​</a></h2><ul><li>Cloudflare account।</li><li>पहले से मौजूद R2 bucket।</li><li>उस Cloudflare project को manage करने की permission जहाँ ImgBed deployed है।</li></ul><h2 id="cloudflare-में-configure-करें" tabindex="-1">Cloudflare में configure करें <a class="header-anchor" href="#cloudflare-में-configure-करें" aria-label="Permalink to &quot;Cloudflare में configure करें&quot;">​</a></h2><h3 id="_1-r2-bucket-बनाएँ" tabindex="-1">1. R2 Bucket बनाएँ <a class="header-anchor" href="#_1-r2-bucket-बनाएँ" aria-label="Permalink to &quot;1. R2 Bucket बनाएँ&quot;">​</a></h3><ol><li>Cloudflare Dashboard में login करें।</li><li><code>R2 Object Storage</code> खोलें।</li><li>Create bucket पर क्लिक करें।</li><li>bucket name चुनें, जैसे <code>imgbed</code>।</li></ol><p>Uploaded files इसी bucket में रखी जाएँगी।</p><p><img src="'+t+'" alt="R2 bucket बनाएँ" loading="lazy"></p><h3 id="_2-bucket-को-imgbed-project-से-bind-करें" tabindex="-1">2. Bucket को ImgBed project से bind करें <a class="header-anchor" href="#_2-bucket-को-imgbed-project-से-bind-करें" aria-label="Permalink to &quot;2. Bucket को ImgBed project से bind करें&quot;">​</a></h3><p>Binding location आपके deployment type पर निर्भर है:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>binding जोड़ते समय ये fields महत्वपूर्ण हैं:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>बनाया हुआ bucket चुनें।</td></tr></tbody></table><p>Variable name बिल्कुल <code>img_r2</code> होना चाहिए। R2 files upload, read और delete करने की सभी क्रियाएँ इसी binding name पर निर्भर हैं।</p><h3 id="_3-project-redeploy-करें" tabindex="-1">3. Project redeploy करें <a class="header-anchor" href="#_3-project-redeploy-करें" aria-label="Permalink to &quot;3. Project redeploy करें&quot;">​</a></h3><p>binding save करने के बाद ImgBed redeploy करें, ताकि Worker या Pages runtime <code>img_r2</code> access कर सके।</p><h2 id="imgbed-में-क्या-दिखेगा" tabindex="-1">ImgBed में क्या दिखेगा <a class="header-anchor" href="#imgbed-में-क्या-दिखेगा" aria-label="Permalink to &quot;ImgBed में क्या दिखेगा&quot;">​</a></h2><p>R2 binding उपलब्ध होने के बाद खोलें:</p><ol><li>System Settings।</li><li>Upload Settings।</li><li><code>Cloudflare R2</code> channel।</li></ol><p>System अपने आप एक fixed channel बनाता है:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>यह fixed binding channel है। इसे create करने के लिए Add Channel पर क्लिक करने की ज़रूरत नहीं है, और इसे normal channel की तरह delete नहीं किया जा सकता।</p><h2 id="admin-panel-में-editable-fields" tabindex="-1">Admin panel में editable fields <a class="header-anchor" href="#admin-panel-में-editable-fields" aria-label="Permalink to &quot;Admin panel में editable fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>क्या करता है</th><th>आवश्यक</th></tr></thead><tbody><tr><td>Enable channel</td><td>R2 upload selection में शामिल होगा या नहीं।</td><td>हाँ</td></tr><tr><td>Account ID</td><td>केवल तब जब quota limits चालू हों और official R2 usage query करना हो।</td><td>quota limits चालू हों तो सुझाया गया</td></tr><tr><td>Bucket name</td><td>केवल तब जब quota limits चालू हों और official R2 usage query करना हो।</td><td>quota limits चालू हों तो सुझाया गया</td></tr><tr><td>Quota limit</td><td>capacity के आधार पर यह R2 channel upload selection में शामिल होगा या नहीं।</td><td>नहीं</td></tr><tr><td>Threshold</td><td>usage specified percentage तक पहुँचने पर इस channel में लिखना बंद करता है।</td><td>quota limits चालू हों तो आवश्यक</td></tr></tbody></table><p>Account ID Cloudflare dashboard के account information panel से copy किया जा सकता है। इसे केवल तब भरें जब आप चाहते हैं कि ImgBed R2 quota usage query और enforce करे।</p><p><img src="'+a+'" alt="Account ID लें" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Cloudflare में R2 bucket बनाएँ।</li><li>ImgBed project की Cloudflare settings खोलें।</li><li>R2 bucket binding जोड़ें।</li><li><code>Variable name</code> को <code>img_r2</code> करें।</li><li>बनाया हुआ R2 bucket चुनें।</li><li>binding save करें और ImgBed redeploy करें।</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings पर लौटें।</li><li>पुष्टि करें कि <code>Cloudflare R2</code> channel दिख रहा है और enabled है।</li></ol><p>अगर आप चाहते हैं कि R2 capacity के आधार पर upload selection में हिस्सा ले, तो quota limit enable करें, फिर save करने से पहले Account ID, bucket name, quota limit और threshold भरें।</p><p><img src="'+d+'" alt="Quota limits configure करें" loading="lazy"></p><h2 id="कैसे-जाँचें" tabindex="-1">कैसे जाँचें <a class="header-anchor" href="#कैसे-जाँचें" aria-label="Permalink to &quot;कैसे जाँचें&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel Upload Settings में दिखाई देता है।</li><li>channel card दिखाता है कि यह enabled है।</li><li>छोटी test file सफलतापूर्वक upload होती है, और लौटाया गया link normally खुलता है।</li><li>अगर file खोलने पर <code>R2 database binding is not configured</code> दिखता है, तो runtime को <code>img_r2</code> binding नहीं मिला। Cloudflare में binding name जाँचें और project redeploy करें।</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
